-- public.books (10 rows)
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('36ab3ccb-f648-45ab-b0ef-c6111d028f04','Alchemised','SenLinYu',NULL,'« La guerre est finie. Que croyez-vous protéger dans votre cerveau ? Holdfast est mort. La Flamme éternelle s''est éteinte.  Il ne vous reste plus personne à sauver... »
Helena Marino était une alchimiste prometteuse. Aujourd''hui, elle n''est plus qu''une prisonnière, captive de la guerre qui a ravagé Paladia et de sa propre mémoire défaillante. Ses amis et alliés de la résistance ont été massacrés, ses pouvoirs neutralisés, et le monde qu''elle connaissait n''est plus qu''un champ de ruines.
Dans l''après-guerre, Paladia est tombée sous le contrôle de guildes corrompues et de nécromanciens dépravés, dont les créatures mortes-vivantes ont assuré le triomphe. Helena est désormais entre leurs mains.
Officiellement, elle n''était qu''une guérisseuse sans importance. Pourtant, les mois qui ont précédé sa capture se sont effacés de sa mémoire, et cette zone d''ombre intrigue. Est-elle vraiment aussi insignifiante qu''on le prétend, ou détient-elle, sans le savoir, la clé du dernier espoir de la résist','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/0b/c0/1c/18661387/1540-1/tsp20251017081825/Alchemised-Edition-francaise.jpg',NULL,'Roman',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-22 16:27:58.11462+00','2025-10-22 16:27:58.11462+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('77ae9e27-5ff1-4644-8a3c-23abc102bb1e','Cuero Assasino - Tome 1','Hazel Diaz',NULL,'Dans les tréfonds des quartiers insalubres de Naples, survit une jeune femme : Ayhan. Livrée à la rue depuis son plus jeune âge, elle a grandi au milieu du vice, de la violence et des bassesses humaines. Mais elle lutte pour ne pas sombrer dans ces travers.

Un soir, affamée, elle s''introduit dans la villa des dirigeants de la mafia, pour y dérober des vivres. Elle tombe alors face à face avec son pire cauchemar : Aslan, l''héritier du clan Dell''Era, l''une des plus importantes organisations mafieuses d''Italie. L''homme aux yeux vairons est aussi fascinant qu''impitoyable.

Le destin les force à se rapprocher, malgré la haine qui les oppose. L''audace d''Ayhan chamboule l''ordre établi au sein de la mafia et du monde d''Aslan.

En dépit de leurs rancunes respectives, Ayhan et Aslan sont rattrapés par leur destin qui les lie fatalement... car certains liens naissent dans la douleur et deviennent impossibles à rompre.','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/28/ee/23/19131944/1540-1/tsp20251018081518/Cuero-Aasino.jpg',NULL,'Roman',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-22 16:30:04.373133+00','2025-10-22 16:30:04.373133+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('401fea54-e17a-4284-b1e0-17798ca6c103','Un palais d''épines et de roses','Sarah J. Maas',NULL,'En chassant dans les bois enneigés, Feyre voulait seulement nourrir sa famille. Mais elle a commis l''irréparable en tuant un Fae, et la voici emmenée de force à Prythian, royaume des immortels.
Là-bas, pourtant, sa prison est un palais magnifique et son geôlier n''a rien d''un monstre. Tamlin, un Grand Seigneur Fae, la traite comme une princesse.
Et quel est ce mal qui ronge le royaume et risque de s''étendre à celui des mortels ?
A l''évidence, Feyre n''est pas une simple prisonnière. Mais comment une jeune humaine d''origine aussi modeste pourrait-elle venir en aide à de si puissants seigneurs ?
Sa liberté, en tout cas, semble être à ce prix.

ATTENTION : Ce roman contient des scènes de sexe explicites. Nous la conseillons à partir de 16 ans','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/f6/97/80/8427510/1540-1/tsp20250620075100/Un-Palais-d-epines-et-de-roses-T1.jpg',NULL,'Fiction',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-22 16:33:51.301542+00','2025-10-22 16:33:51.301542+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('b0c4ddfe-ef8d-4de7-a17c-80c7b89b643b','Le bouquin des méchancetés et autres traits d''esprit','François Xavier Testu',NULL,'La méchanceté est un art à la condition d''être drôle et inspirée. Préfacé par un maître du genre, Philippe Alexandre, cet ouvrage offre le florilège le plus complet et jubilatoire qui soit des traits d''esprit, saillies, épigrammes et autres " vacheries " qui ont jalonné l''histoire littéraire, mondaine et politique de l''Antiquité à nos jours.
Certaines époques et certains milieux se sont particulièrement illustrés dans cet exercice vivifiant : les cercles littéraires des XVIe et XVIIe siècles, les salons et la cour de France au siècle des Lumières, le monde politique et la société mondaine de la IIIe République, l''Angleterre postvictorienne, la grande période hollywoodienne de l''entre-deux-guerres... Autant de moments où la liberté d''esprit et une lucidité aiguisée se sont exprimées sans crainte de démystifier et tourner en ridicule les figures installées du conformisme intellectuel et de l''académisme pontifiant.
Parmi les experts en la matière, on trouve de grands hommes d''État. Clemen','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/dc/77/5d/6125532/1540-1/tsp20251016075333/Le-bouquin-des-mechancetes-et-autres-traits-d-esprit.jpg',NULL,'Anthologie',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 10:39:01.28378+00','2025-10-23 10:39:01.28378+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('26b3f69c-df4d-4803-ba8f-b7e745ed6f67','Oeuvres de H.P. Lovecraft - tome 1','Howard Phillips Lovecraft',NULL,'Le plus grand écrivain américain après Edgar Poe dans le domaine du fantastique, Howard Phillips Lovecraft (1890-1937) reste aussi méconnu que lui dans son pays d''origine. Écrits dès l''âge de six ans, ses Premiers Contes - inédits en français - révèlent pourtant le génie précoce de celui qui allait rénover le fantastique en lui donnant une dimension cosmique. En deux romans et dix-huit nouvelles, Lovecraft imagine que les prodiges et les monstres du folklore européen (fantômes, sorciers, vampires), les abîmes temporels des religions orientales, les fables et légendes de l''Antiquité ne sont que les manifestations d''un culte secret unique. Culte de l''immense et monstrueux Cthulhu, l''un des Grands Anciens qui régnèrent il y a des millions d''années sur la Terre et rêvent de la reconquérir. Regroupés pour la première fois, alors qu''ils étaient dispersés chez des éditeurs différents, ces vingt textes permettent de suivre la montée du mythe de Cthulhu dans l''inspiration de Lovecraft de 1917 à','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/6c/14/03/201836/1540-1/tsp20251002073339/oeuvres-de-H-P-Lovecraft-tome-1-NE.jpg',NULL,'Roman',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 10:41:03.421607+00','2025-10-23 10:41:03.421607+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('421452a5-cdae-497e-a9a6-33868a57ca0a','J''ai un mot à vous dire - Et autres fantaisies sur la langue française','Jean-Loup Chiflet',NULL,'Les grands succès de Jean-Loup Chiflet sur les subtilités de la langue française, ses mots bizarres et incongrus, ses clichés et ses expressions toutes faites, enfin réunis en un seul volume !

Il jongle et batelle, il funambule et acrobate avec bonheur... Depuis un certain temps, et peut-être même davantage, Jean-Loup Chiflet fait son cirque avec les mots. À force de les modeler, de les palper, de les chatouiller, de les titiller, bref, de les malaxer, il lui a pris l''incoercible envie de tout savoir sur eux, à l''image du dompteur qui doit bien connaître ses fauves pour être à même d''anticiper leurs humeurs et leurs réactions.
Ce " Bouquin " offre ainsi un florilège de ses meilleurs ouvrages consacrés au français et à ses bizarreries. C''est une déclaration d''amour à ces mots en qui Victor Hugo voyait de véritables " êtres vivants ", et qui semblent souvent mener leur existence propre. On y retrouve tout ce qui fait la substantifique et immuable moelle des livres de Jean-Loup Chiflet :','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/15/29/14/18098453/1540-1/tsp20250827081208/J-ai-un-mot-a-vous-dire-Et-autres-fantaisies-sur-la-langue-francaise.jpg',NULL,'Méthode de langue',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 10:43:40.448049+00','2025-10-23 10:43:40.448049+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('b9104cdb-931f-41ce-bb68-aae020bbe767','Histoire de Jérusalem','Vincent Lemire',NULL,'4 000 ans d''une histoire universelle pour la première fois racontés dans une BD exceptionnelle.

Il y a 4 000 ans, Jérusalem était une petite bourgade isolée, perchée sur une ligne de crête entre la Méditerranée et le désert. Aujourd''hui, c''est une agglomération de presque un million d''habitants, qui focalise les regards et attire les visiteurs du monde entier.
Entre-temps, les monothéismes y ont été inventés, les plus grands conquérants s''en sont emparé, les plus grands empires s''y sont affrontés. Tour à tour égyptienne, perse, juive, grecque, romaine, byzantine, arabe, croisée, mamelouke, ottomane, anglaise, jordanienne, israélienne et palestinienne, Jérusalem est au coeur des intérêts et des passions du monde. Berceau du judaïsme, du christianisme et de l''islam, elle est aujourd''hui une capitale spirituelle pour plus de la moitié de l''humanité.
En 10 chapitres, acteurs et témoins, célèbres ou anonymes, toutes celles et ceux qui ont arpenté Jérusalem au fi l des siècles racontent ce','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/73/9d/dd/14523763/1540-1/tsp20250923084424/Histoire-de-Jerusalem.jpg',NULL,'Bande dessinée',NULL,'1','1','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 10:46:40.027916+00','2025-10-23 10:46:40.027916+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('1bef9591-a637-4eb0-8613-8e5db42138f1','The Circle of Days','Robert Laffont',NULL,'Seft est tailleur de silex. Sous la chaleur estivale, il traverse la Grande Plaine pour participer aux célébrations du solstice d''été qui marquent une nouvelle année. Il espère y vendre le fruit de son travail... et revoir Neen dont il est épris. Issue d''une famille puissante d''éleveurs, la jeune fille pourrait lui offrir une nouvelle vie, loin de la violence de son clan.
Mais c''est Joia, la soeur de Neen, qui va changer le destin de tous. Visionnaire et déterminée, elle rêve de bâtir un immense cercle de pierres pour rassembler les communautés ennemies de la plaine. À ses côtés, Seft va s''engager dans un projet fou : ériger un monument sacré, malgré la sécheresse, les mauvaises récoltes et les conflits qui s''intensifient. Mais quand un acte d''une cruauté insoutenable déclenche la guerre, le rêve de paix et d''unité menace de s''effondrer...
Dans son nouveau roman, Ken Follett, le maître incontesté du roman épique, explore les origines de l''un des plus grands mystères de l''humanité : les','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/fb/d4/20/18928891/1540-1/tsp20251003081708/Le-Cercle-des-jours.jpg',NULL,'Roman','2016','7','6','73452f8e-146b-42dd-9855-d5805069f276','2025-10-22 16:24:50.216204+00','2025-10-22 16:24:50.216204+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('8571325b-9df5-4c92-b450-a6905364ff67','Histoir de france t17 louis xvi','Jules Michelet',NULL,'"Louis XVI n''eut rien de la France, ne la soupçonna même pas.
De race et par sa mère, il était un pur Allemand, de la molle Saxe des Augustes, obèse et alourdie de sang, charnelle et souvent colérique. Mais, à la différence des Augustes, son honnêteté naturelle, sa dévotion, le rendirent régulier dans ses moeurs, sa vie domestique. En pleine cour il était solitaire, ne vivant qu''à la chasse, dans les bois de Versailles, à Compiègne ou à Rambouillet. C''est uniquement pour la chasse, pour conserver ses habitudes, qu''il tint les États généraux à Versailles (si près de Paris) ! S''il n''eût vécu ainsi, il serait devenu énorme, comme les Augustes, un monstre de graisse, comme son père le Dauphin, qui dit lui-même, à dix-sept ans, "ne pouvoir traîner la masse de son corps. " Mais ce violent exercice est comme une sorte d''ivresse. [. ] Il n''était nullement crapuleux comme Louis XV. Mais c''était un barbare, un homme tout de chair et de sang. De là sa dépendance de la reine. [. ] Nul roi ne montr','https://static.fnac-static.com/multimedia/FR/Images_Produits/FR/fnac.com/Visual_Principal_340/1/7/8/9782849900871/tsp20120921145728/Louis-XV-et-Louis-XVI.jpg',NULL,'Etude',NULL,'3','2','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 10:49:19.114997+00','2025-10-23 10:49:19.114997+00') ON CONFLICT DO NOTHING;
INSERT INTO public.books (id, title, author, isbn, description, cover_url, pdf_url, category, publication_year, total_copies, available_copies, owner_id, created_at, updated_at) VALUES ('9be131e7-b8e8-4cdb-a87a-fecc51dfcdc4','Dictionnaire des symboles','Alain Gheerbrant  Jean Chevalier',NULL,'C''est trop peu de dire que nous vivons dans un monde de symboles, un monde de symboles vit en nous. De la psychanalyse à l''anthropologie, de la critique d''art à la publicité et à la propagande idéologique ou politique, sciences, arts et techniques essaient de plus en plus aujourd''hui de décrypter ce langage des symboles, tant pour élargir le champ de la connaissance et approfondir la communication que pour apprivoiser une énergie d''un genre particulier, sous-jacente à nos actes, à nos réflexes, à nos attirances et répulsions, dont nous commençons à peine à deviner la formidable puissance.
Des années de réflexions et d''études comparatives sur un corpus d''informations rassemblées par une équipe de chercheurs, à travers des aires culturelles recouvrant la durée de l''histoire et l''étendue du peuplement humain, les auteurs ont tenté de donner à voir le cours profond du langage symbolique, tel qu''il se ramifie dans les strates cachées de notre mémoire.
Chacun sentira bien l''importance de ce','https://static.fnac-static.com/multimedia/PE/Images/FR/NR/0b/55/04/283915/1540-1/tsp20250826080055/Dictionnaire-des-symboles.jpg',NULL,'Dictionnaire et encyclopédie','2020','10','10','73452f8e-146b-42dd-9855-d5805069f276','2025-10-23 11:04:40.802212+00','2025-10-23 11:04:40.802212+00') ON CONFLICT DO NOTHING;

